import React from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "../styles/landing.css";

const Navbar = () => {
  const navigate = useNavigate();
  const { isAuthenticated, logout, user } = useAuth();

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  const goToDashboard = () => {
    if (user?.role) {
      navigate(`/${user.role}/dashboard`);
    }
  };

  return (
    <nav className="navbar">
      {/* LOGO */}
      <div className="logo" onClick={() => navigate("/")}>
        <div className="logo-box">🎁</div>
        Freelancing Platform
      </div>

      {/* RIGHT SIDE */}
      <div className="nav-links">
        {isAuthenticated ? (
          // Logged in → show Dashboard link + Logout
          <>
            <span className="nav-link" onClick={goToDashboard}>
              Dashboard
            </span>
            <button onClick={handleLogout} className="get-started">
              Logout
            </button>
          </>
        ) : (
          // Not logged in → show Login + Get Started
          <>
            <span className="nav-link" onClick={() => navigate("/login")}>
              Login
            </span>
            <button
              onClick={() => navigate("/register")}
              className="get-started"
            >
              Get Started
            </button>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
